const event = $('Fetch Ingested Events').item.json || {};
const orchestratorResult = $json || {};
const normalized = event.normalized || {};
const source = event.source || normalized.source || 'event';
const eventType = event.event_type || normalized.event_type || 'evento';
const repo = event.repo || normalized.repo || '';
const actor = event.actor || normalized.actor || 'system';
const entityType = normalized.entity_type || event.entity_type || '';
const entityId = normalized.entity_id || event.entity_id || '';
const prNumber = normalized.pull_request_number || event.pull_request_number || null;
const cardId = normalized.trello_card_id || event.trello_card_id || null;
const branch = normalized.branch || event.branch || null;
const correlationId = event.correlation_id || normalized.correlation_id || null;
const url = normalized.url || null;

const lines = [];
lines.push('[PetSafe/' + source + '] ' + eventType);
if (actor) lines.push('Actor: ' + actor);
if (repo) lines.push('Repo: ' + repo);
if (entityType || entityId) lines.push('Entity: ' + [entityType, entityId].filter(Boolean).join(' '));
if (prNumber) lines.push('PR: #' + prNumber);
if (cardId) lines.push('Card: ' + cardId);
if (branch) lines.push('Branch: ' + branch);
if (correlationId) lines.push('Correlation: ' + correlationId);
if (orchestratorResult.assigned_agent || orchestratorResult.routed === false) {
  lines.push('Orchestrator: ' + (orchestratorResult.assigned_agent || 'None'));
}
if (url) lines.push(url);

const content = lines.join('\n').slice(0, 1900);

return [{
  json: {
    ...event,
    orchestrator_result: orchestratorResult,
    outbox_target: 'discord',
    outbox_action: 'notify',
    outbox_idempotency_key: event.event_id || correlationId || null,
    outbox_payload: { content }
  }
}];
